var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 연합 전대 작전 <color=#ffd34c>커튼콜</color>\\n작전 개시 3시간 전","JPN":"管理局連合戦隊作戦<color=#ffd34c>カーテンコール</color>\\n作戦開始3時間前","ENG":"Administration Coalition Divisions Operation <color=#ffd34c>Curtain Call</color>\\n3 hours before commencing operation","TWN":"管理局聯合戰隊作戰<color=#ffd34c>謝幕</color>\\n作戰開始前3小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……그게 무슨 소리야?","JPN":"……どういうことだ？","ENG":"...What are you talking about?","TWN":"……那是什麼意思？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우린 네가 그 화재에서 카운터로 각성한다는 걸 알고 있었어.","JPN":"私たちはあの火災現場であなたがカウンターとして覚醒することを知っていた。","ENG":"We knew you'd awaken as a Counter in that fire.","TWN":"我們知道你會在這場大火中覺醒，成為制裁者。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"물론, 카운터의 각성은 필연적이라 그걸 바꾸면 무슨 일이 발생할지 모르지만…….","JPN":"もちろん、カウンターの覚醒は必然のことだから……それを変えてしまったら何が起こるかわからないけど……","ENG":"Of course, a Counter's awakening is inevitable, so we don't know what would've happened if it changed...","TWN":"制裁者的覺醒不可避免，如果發生改變，不知道會發生什麼事情……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래, 더는 변명하지는 않을게.","JPN":"そうね、これ以上の言い訳はやめるよ。","ENG":"but I won't make any more excuses.","TWN":"好吧，我不會再找任何藉口了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 관리국에…… 그리고 야크샤에게 반드시 필요한 사람이었기 때문이었어.","JPN":"あなたが管理局に……そしてヤクシャーに必ず必要な人間だったからよ。","ENG":"It was because... you were someone the Administration and Yaksha needed.","TWN":"你對於管理局……對於夜叉來說，都是不可缺少的存在。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 우린 그 화재에서 너를 선택한 거야.","JPN":"だから私たちは、あの火災であなたを選択したの。","ENG":"That's why we chose you in that fire.","TWN":"這就是為什麼我們在那場大火中選擇了你。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 우리의 최선이었어.","JPN":"それが私たちにとっての最善だった。","ENG":"That was our best outcome.","TWN":"那是我們最好的結果。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"최선, 최선……!! 그딴 개소리 집어 치워!!","JPN":"最善、最善って、いいかげんにしろ！！","ENG":"Stop saying that word, \\"best!\\"","TWN":"最好的，最好的……！！別說那些屁話！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내 어딜 보고 최선이었다는 거야!!","JPN":"アタシの何が最善なんだ！！","ENG":"How was I the best outcome?!","TWN":"我哪裡看起來是最好的了！！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 망할 귀랑 꼬리 때문이야!? 아니면 내가 환상종 인자를 물려받았기 때문이야!?","JPN":"このくそ耳と尻尾のせいか！？　アタシが幻想種の因子を受け継いでいるから！？","ENG":"Because of these stupid ears and tail?! Or because I carry the Bygone Factor?!","TWN":"是因為這該死的耳朵和尾巴嗎？！還是因為我繼承了夢幻品種因子？！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 대장님과 동료들……! 그 아이가 죽어야만 했던 이유냐고……!?","JPN":"隊長と仲間たち……あの子が死ななければならなかった理由になるのかよ！？","ENG":"Was that enough of a reason...! To kill Captain, my colleagues, and that kid...?!","TWN":"隊長，還有同伴……！還有那個孩子為什麼必須死……？！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대답해!! 주디 스위프트!!","JPN":"答えろ、ジュディ・スウィフト！！","ENG":"Answer my question!! Judy Swift!!","TWN":"回答我！！茱蒂·斯威福特！！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국이……!! 너희가 나한테 바라는 게 대체 뭐야……!?","JPN":"管理局は……！！　おまえらはアタシに何を求めている……！？","ENG":"What does the Administration...!! Or you want from me...?!","TWN":"管理局……！！到底想從我這裡得到什麼……？！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"야크샤의 우두머리.","JPN":"ヤクシャーのリーダー。","ENG":"The head of Yaksha.","TWN":"夜叉的領袖。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국은 널 야크샤의 전대장으로 추천했어.","JPN":"管理局はあなたをヤクシャーの戦隊長として推奨した。","ENG":"The Administration recommended you as the Commander of the Yaksha Division.","TWN":"管理局推薦你當夜叉戰隊長。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리는 거기에 동의했고. 그게 그 화재에서 우리가 널 구한 이유야.","JPN":"そして私たちはそれに同意した。それがあの火災であなたを助けた理由よ。","ENG":"And we agreed to it. That's why we saved you in that fire.","TWN":"我們同意了。這就是我們把你從火災中救出來的原因。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 무슨 소리야……?","JPN":"どういうことだ……？","ENG":"What are you saying...?","TWN":"你在說什麼……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내가 왜 야크샤의 전대장이 되어야 한다는 거야? 라이오넬 전대장은?","JPN":"なぜアタシがヤクシャーの戦隊長にならなきゃいけないんだ……？　ライオネル戦隊長は？","ENG":"Why am I supposed to be the Yaksha's Commander? What about Commander Lionel?","TWN":"為什麼一定要我成為夜叉的戰隊長？萊諾戰隊長呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야크샤는 줄곧 라이오넬 전대장을 찾고 있었다면서!","JPN":"ヤクシャーはずっとライオネル戦隊長を探しているんだろ！","ENG":"You told me that Yaksha's been searching for Commander Lionel all this time!","TWN":"夜叉不是一直在尋找萊諾戰隊長嗎！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……자세한 이유는 우리도 몰라.","JPN":"……詳しいことは私たちにもわからない。","ENG":"...We also don't know the exact details.","TWN":"……我們不知道具體的原因。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 인과를 연산하는 테라브레인의 집합체. 하이브 컨트롤.","JPN":"でも因果を演算するテラブレインの集合体、ハイブコントロールが。","ENG":"But the Terrabrain cluster that does causality calculation, Hive Control.","TWN":"但是，運算因果的特拉大腦集合體……巢穴控制系統。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 하이브 컨트롤이 널 선택했다는 건 미래에 중요한 분기점 역할을 하게 된다는 뜻이야.","JPN":"あのハイブコントロールがあなたを選んだということは、あなたは未来の重要な分岐点として役割を担うということよ。","ENG":"Having Hive Control choose you means that you'll serve as an important turning point in the future.","TWN":"是巢穴控制系統選擇了你，就表示你將成為未來的一個重要轉捩點。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 관리국이 널 차기 전대장으로 추천한 이유, 우리가 그 화재에서 널 구한 이유…….","JPN":"それが管理局があなたを次の戦隊長として推奨した理由。私たちがあなたをあの日助けた理由よ。","ENG":"That's the reason why the Administration recommended you as the next Commander, and why we saved you in that fire...","TWN":"這就是為什麼管理局推薦你擔任下一任戰隊長，也是為什麼我們從那場大火中救了你……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 틀림없이, 이 세계에 있어서 <color=#ffd34c>최선</color>의 결과겠지.","JPN":"そしてその選択は、間違いなくこの世界にとって<color=#ffd34c>最善</color>の結果になるでしょう。","ENG":"And without a doubt, that was the <color=#ffd34c>best</color> outcome for this world.","TWN":"而且，這一定是對這個世界<color=#ffd34c>最好</color>的結果。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 무슨……?","JPN":"それは……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"지금껏 숨겨서 미안해.","JPN":"今まで隠してごめんなさい。","ENG":"I'm sorry for hiding it all this time.","TWN":"我很抱歉瞞著你。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리를 원망하려면, 얼마든지 원망해도 좋아.","JPN":"私たちを恨みたければ、いくらでも恨んでいい。","ENG":"You have every right to blame us if you want.","TWN":"如果你想責怪我們，就儘管責怪吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 네가 죄책감 같은 걸 느낄 필요는 없어. 앨리스.","JPN":"でもあなたが自分を責める必要はないよ、アリス。","ENG":"But there's no need for you to feel guilty, Alice.","TWN":"但你不需要感到內疚，艾莉絲。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"죄책감을 느낄 필요가 없어……?","JPN":"自分を責める必要がない……？","ENG":"No need to feel guilty...?","TWN":"不需要感到內疚……？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제길, 웃기지 말라고!","JPN":"くそ、ふざけんな！","ENG":"Dammit! Don't be ridiculous!","TWN":"該死的，別開玩笑了！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……대장님.","JPN":"……隊長。","ENG":"...Captain.","TWN":"……隊長。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이제 제가 대체 무슨 면목으로 당신을……!","JPN":"アタシはこれからあなたにどう接すれば……！","ENG":"How am I supposed to see you now...?!","TWN":"我現在到底拿什麼臉去面對你……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"저…….","JPN":"あの……","ENG":"Excuse me...?","TWN":"那個……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"그 고양이 귀……. 브레이드우드 소방관님 맞으세요……?","JPN":"その猫耳……ブレイドウッド消防士さんですか……？","ENG":"Those cat ears... Are you, Officer Braidwood...?","TWN":"這個貓耳朵……你是布雷德伍德消防員嗎……？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"현장에서 당신을 봤어요. 꼭 만나 뵙고 싶었는데 건강 문제로 장기 휴직 중이시라고…….","JPN":"現場であなたを見ました。ぜひ一度お会いしたかったけど、体調不良で長期求職中だと……","ENG":"I saw you on the scene of the fire. I really wanted to meet you, but was told that you were on a long-term leave due to health issues...","TWN":"我在現場看到過你。我一直很想見見你，但聽說你因為健康問題正在休長假……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제길, 아직도 날 쫓는 기자가 있었나……!","JPN":"くそ、まだアタシを追ってる記者がいたのか……！","ENG":"Gah, there are reporters still chasing me around...?!","TWN":"可惡，這些記者就不能放過我嗎……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"자, 잠깐만요! 가지 마세요, 소방관님! 아무한테도 말하지 않을게요!","JPN":"ま、待ってください！　消防士さん！　誰にも言いません！","ENG":"W-wait! Officer, don't go! I won't tell anyone!","TWN":"等、等一下！別走，消防員！我不會告訴任何人的！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"저 노라의 엄마예요! 그 화재에서 소방관님께서 안고 나오셨던 아이의……!","JPN":"私はノラの母です。あの火災で、あなたが運び出してくださった子どもの……！","ENG":"I'm Nora's mother! The mother of the child you carried out of that fire...!","TWN":"我是諾拉的媽媽！就是你從火場救出來的孩子的……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……네?","JPN":"……え？","ENG":"...What?","TWN":"……嗯？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"죄송합니다. 제가 먼저 유족분을 찾아뵀어야 했는데…….","JPN":"すみません。遺族の方に……アタシから伺うべきだったのに……","ENG":"I'm sorry. I should've visited you first...","TWN":"對不起。本應該是我去探望她的家屬的……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"사과하지 않으셔도 돼요. 소방관님의 잘못이 아니잖아요.","JPN":"謝らないでください。ブレイドウッドさんのせいじゃありませんから。","ENG":"No need to apologize. It wasn't your fault.","TWN":"你不必道歉。這不是你的錯。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아닙니다! 저는……!","JPN":"違います！　アタシは……！","ENG":"No! I...!","TWN":"不！我……！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"……그 아이 원래부터 몸이 약했거든요.","JPN":"……あの子、元々体が弱かったんです。","ENG":"...She was weak even before that.","TWN":"……那孩子的身體一直不好。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……네?","JPN":"……え？","ENG":"…Pardon?","TWN":"……嗯？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"희귀병이었어요. 병원에서도 원인을 알 수가 없다고 하더군요.","JPN":"難病を患っていて……病院でも原因がわからないと言っていました。","ENG":"She had a rare disease. Even the hospital said they couldn't determine what it was.","TWN":"諾拉得了一種罕見的疾病。就連醫院也無法確定病因。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"다른 아이들이 뛰놀며 학교에 다닐 때, 인생의 대부분을 병원에서 보냈죠.","JPN":"同年代の子どもたちが学校に通い、自由に走り回っている間……あの子は人生の大半を病院で過ごしました。","ENG":"While kids her age were running around and going to school, she spent most of her days at the hospital.","TWN":"當其他孩子活蹦亂跳能夠去上學的時候，她大部分時間都在醫院裡度過。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"부모로서 부끄럽지만……. 그 애를 떠나보낼 마음의 준비를 하고 있었거든요.","JPN":"親としてこういうことを言うのは恥ずかしいのですが……私はあの子と別れる心の準備をしていたんです。","ENG":"I'm ashamed to admit this as a parent, but... I was getting ready to say goodbye to her.","TWN":"作為家長我很羞愧……我已經做好了放她離開的心裡準備。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"이렇게 갑작스럽게 떠나게 될 줄은 몰랐지만…….","JPN":"その瞬間がこんなに突然訪れるとは、思いませんでしたけれど。","ENG":"I didn't expect her to pass so suddenly, but...","TWN":"但我沒想到會這麼突然……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"저, 소방관님께 줄곧 감사하다는 인사를 전하고 싶었어요.","JPN":"私はずっと、消防士さんにお礼を言いたかったんです。","ENG":"I just wanted to thank you, Officer.","TWN":"我一直想對消防員們說聲謝謝。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"소방관님은 그 화재 속에서 마지막까지 그 아이를 포기하지 않으셨잖아요.","JPN":"あなたはあの炎の中、最後まであの子を諦めなかった。","ENG":"You didn't give up hope on her in that fire until the very end.","TWN":"直到最後，你們、你都沒有放棄那個孩子。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"저는……. 너무나도 쉽게 딸 아이의 병치료를 포기했었는데…….","JPN":"私は……あんなに簡単に、娘の治療を諦めていたのに……","ENG":"But I... I gave up on treating my daughter's illness so quickly...","TWN":"我……我卻準備輕易地放棄女兒的治療……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"그래서……. 그 아이한테 너무 미안하고…….","JPN":"だから……娘に合わせる顔がなくて……","ENG":"I'm... so sorry for her and...","TWN":"所以……我對不起那孩子……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"얼굴도 모르는 그 애의 마지막을 지켜준 소방관님께 너무 감사해서…….","JPN":"でも、見知らぬ他人のあの子を、最後まで守ってくださった消防士さんにお礼を伝えたくて……","ENG":"also grateful to the firefighter who protected her until the end...","TWN":"非常感謝你……直到最後依然守護著那個未曾謀面的孩子……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……아닙니다.","JPN":"……いいえ。","ENG":"...I was just doing my job.","TWN":"……不是的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저는 당신에게 그런 인사를 받을 자격이 없습니다.","JPN":"アタシは感謝を言われる資格なんてありません。","ENG":"So I don't deserve any gratitude from you.","TWN":"我不值得你的感謝。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대장님도, 동료들도……. 그리고 따님도…….","JPN":"隊長も、仲間たちも……そして娘さんも……","ENG":"Captain, my colleagues... and even your daughter...","TWN":"隊長和同伴們……還有你的女兒……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"결국, 저 때문에 그렇게 된 거나 다름이 없으니까요.","JPN":"アタシのせいでそうなってしまったんですから。","ENG":"They all... died because of me.","TWN":"說到底，都是因為我才不在的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"거기에 제가 있었기 때문에…….","JPN":"あそこに、アタシがいたせいで……","ENG":"Because I was there–","TWN":"就因為我當時在那裡……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"그 화재로 동료분들을 많이 잃으셨다고 들었어요.","JPN":"あの火災で同僚の方々が多く亡くなられたと聞きました。","ENG":"I heard you lost a lot of colleagues to that fire.","TWN":"我聽說你在那場火災中失去了很多同事。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"하지만 최선을 다하셨는데, 그렇게까지 자책하실 필요는 없다고 생각해요.","JPN":"でも、ベストを尽くしたのにそこまで自分を責める必要はないと思います。","ENG":"But you did your best, so there's no need to keep blaming yourself.","TWN":"但你已經盡力了，我認為你不必太自責。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"혹시…… 소방관을 그만두실 생각인가요?","JPN":"もしかして……消防士をお辞めになるのでしょうか。","ENG":"Are you... thinking of quitting being a firefighter?","TWN":"你……是想辭去消防員的職務嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"네……?","JPN":"え……？","ENG":"What...?","TWN":"嗯……？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"이기적인 바람일 수도 있지만, 저는 소방관님이 그만두지 않았으면 좋겠어요.","JPN":"身勝手なお願いかもしれませんが、私は消防士を辞めて欲しくありません。","ENG":"It may be selfish of me to wish this, but I hope that you don't quit being a firefighter.","TWN":"雖然這很自私，但我不希望你這麼做。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"적어도 그 아이는 소방관님이 그만두길 원치 않을 테니까.","JPN":"あの子も、消防士さんに仕事を辞めて欲しくないと思っているはずです。","ENG":"Or at least, my daughter wouldn't have wanted you to.","TWN":"至少這個孩子不會希望你就這麼放棄的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"자기 때문에 죄책감을 느끼기를 바라지 않을 테니까요.","JPN":"自分のせいで、罪悪感を抱いて欲しくないと。","ENG":"She wouldn't want you to feel guilty because of her.","TWN":"她也不想讓你因為她而感到愧疚。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"그 아이, 아프기 전에는 소방관님처럼 남을 돕는 게 꿈이었어요.","JPN":"あの子、病気になる前は消防士さんみたいに人を助ける仕事に就くのが夢だったんです。","ENG":"Before my daughter got sick, she also dreamt of helping others like you.","TWN":"在生病之前，她的夢想是像消防員一樣幫助別人。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"그러니까……. 소방관님께서 그 아이의 몫까지 조금 더 힘을 내주셨으면 좋겠어요.","JPN":"ですから……あの子の分まで、元気を出して頑張って欲しいです。","ENG":"So... I can only hope that you keep helping others for her sake.","TWN":"所以……我希望你以後能繼續加油，帶上那個孩子的份。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 현실 전초기지, <color=#ffd34c>쉘터 No.72</color>\\n관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 임시 본부","JPN":"管理局現実前哨基地、<color=#ffd34c>シェルターNo.72</color>\\n管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>臨時本部","ENG":"Administration's Normalside Frontier Base, <color=#ffd34c>Shelter No. 72</color>\\nAdministration 4th Recon Division <color=#ffd34c>Yaksha</color>'s temporary HQ","TWN":"管理局現世前哨站，<color=#ffd34c>72號庇護所</color>\\n管理局第4偵察戰隊<color=#ffd34c>夜叉</color>臨時總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무슨 소란이야?","JPN":"なんの騒ぎだ？","ENG":"What's going on?","TWN":"發生什麼事了！？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"아, 브레이드우드 씨! 큰 일 났어요!","JPN":"あ、ブレイドウッドさん！　大変です！","ENG":"Oh, Ms. Braidwood! We're in trouble!","TWN":"啊，布雷德伍德！大事不好了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"작전에 투입된 관리국 연합 전대가 고전하고 있는 모양이에요!","JPN":"作戦に投入された管理局の連合戦隊が苦戦しているようです！","ENG":"It seems the Administration's coalition divisions sent into the operation is struggling!","TWN":"參與作戰的管理局聯合戰隊的情況似乎不太好！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"야크샤 전대와의 연락이 두절됐다고, 다들 걱정하고 있어요!","JPN":"ヤクシャー戦隊との連絡が途切れて、皆心配しているんです！","ENG":"Their comms with the Yaksha Division have gone silent, so everyone is worried!","TWN":"我們與夜叉戰隊失去了聯繫，大家都很擔心！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐라고? 야크샤가?","JPN":"何だと……？　ヤクシャーと連絡が？","ENG":"What? Yaksha?","TWN":"什麼？夜叉？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼, 부전대장은……? 주디 스위프트는 어떻게 됐어……!","JPN":"じゃあ、副戦隊長は……？　ジュディ・スウィフトはどうなったんだ……！","ENG":"Then what about Deputy Commander...? What happened to Judy Swift...?!","TWN":"那麼，副戰隊長……？茱蒂·斯威福特怎麼了……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"자세한 건 저도 잘 모르지만…….","JPN":"詳しいことはわかりませんが……","ENG":"I don't know the details, but...","TWN":"詳細情況不清楚，但是……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"관리국에서는 이미 추가 전대 투입을 결정한 것 같아요.","JPN":"管理局は、追加兵力を送ることを決めたようです。","ENG":"I think the Administration has already decided to send in more troops.","TWN":"管理局似乎已經決定增派戰隊了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"정보 공유를 목적으로 다른 전대의 전대장께서 이 전초기지에 방문하셨거든요.","JPN":"情報共有のために、他の戦隊の戦隊長がこの前哨基地を訪ねたんです。","ENG":"Another division Commander visited the base for the purpose of sharing intel.","TWN":"為了共用資訊，其他戰隊的戰隊長也到訪了這個前哨基地。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다른 전대의 전대장?","JPN":"他の戦隊の戦隊長？","ENG":"Another division's Commander?","TWN":"其他戰隊的戰隊長？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"네, 지금 닥터 메이시와 같이 계십니다.","JPN":"はい、今ドクター・メイシと一緒にいます。","ENG":"Yes. She's with Dr. Macy right now.","TWN":"嗯，現在和梅西博士在一起。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"관제사를 지망하시던 분이라, 야크샤 전대의 기술을 직접 보고 싶다고…….","JPN":"管制官を目指していた方なんで、ヤクシャー戦隊の技術を直接見てみたいと……","ENG":"She aspired to be an operator, so she wanted to see the Yaksha Division's technology in person...","TWN":"她曾有意成為飛航管制員，所以想親眼看看夜叉戰隊的技術……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제길……!","JPN":"くそ……！","ENG":"Dammit...!","TWN":"可惡……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이 장치를 함선에 탑재하면, 엘리시움 그림자의 침식파를 추적할 수 있다는 건가?","JPN":"この装置を艦船に搭載すると、エリシウムシャドウの侵食波を追跡できるということだな。","ENG":"So mounting this device onto the ship will allow the tracking of Elysium Shadows' Corruption ray?","TWN":"就是說如果將這個裝置安裝在艦船，就可以追蹤樂團暗影的侵蝕波？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그렇습니다요.","JPN":"その通りでやんす。","ENG":"That's correct.","TWN":"沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 그렇다면 탑재까지 시간이 얼마나…… ","JPN":"うむ。では搭載まではどれぐらいの時間が…… ","ENG":"Very well. Then how long will it take to install...","TWN":"好。那麼搭載需要多長時間……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"완두콩, 지금 필하모닉 홀에 있는 연합 전대를 지원하러 가는 거지?","JPN":"ちんちくりん、今フィルハーモニーホールにいる連合戦隊の支援に行くんだろ？","ENG":"Green pea, you're going to Philharmonic Hall to help the coalition divisions, right?","TWN":"豌豆，你要去管弦樂廳支援聯合戰隊嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼 나도 가겠어.","JPN":"じゃあアタシも行く。","ENG":"Then take me with you.","TWN":"那也帶上我吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"완두콩……?","JPN":"ちんちくりん……？","ENG":"Green pea...?","TWN":"豌豆……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 자네는 저번 정기 회의에서 소란을 일으킨……?","JPN":"そういえば、君は先日の定例会議で騒ぎを起こした……？","ENG":"Hold on, aren't you the one who caused the commotion in the regular meeting...?","TWN":"等等，你是在上次定期會議搗亂的……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이 허접 고양이가 지금 무슨 말을 하는 겁니까요!","JPN":"このヘタクソ猫、何訳のわからないこと言ってるでやんす！","ENG":"What's this noob cat even talking about right now?!","TWN":"你現在說什麼呢，臭貓！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"허접 고양이……?","JPN":"ヘタクソ猫……？","ENG":"Noob cat...?","TWN":"臭貓……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그새 부전대장님의 말을 잊으셨습니까요?","JPN":"副戦隊長の言葉、もう忘れたでやんすか？","ENG":"Did you already forget Deputy Commander's orders?","TWN":"你忘了副戰隊長說的話了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"신참 녀석만큼은 절대 이 작전에 껴서는 안 된다고 하지 않았습니까요!","JPN":"新入りだけは絶対この作戦に参加しちゃダメだって言ったじゃないでやんすか！","ENG":"She said that the rookie would absolutely not be allowed to participate in this operation!","TWN":"新人絕對不能參與這次作戰！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"지금 그 잘난 부전대장님이 위험에 빠진 거 아니야?","JPN":"で、その副戦隊長が今、ピンチなんだろう？","ENG":"But isn't that same Deputy Commander in danger right now?","TWN":"但副戰隊長現在不是有危險嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야크샤 전대는 서로 가족이나 다름없다면서? 넌 그 꼴을 지켜만 볼 셈이야?","JPN":"ヤクシャー戦隊は皆家族同然って言ってなかったか？　おまえはその家族を見捨てるつもりなのか？","ENG":"I thought we were all family in Yaksha. So you're just going to do nothing and watch?","TWN":"而且副戰隊長還說過，夜叉隊員之間就像家人一樣？還是說你就打算眼睜睜地看著悲劇發生嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아, 아무튼 안 되는 겁니다요!","JPN":"と、とにかくダメなものはダメでやんす！","ENG":"A-anyway! You're not going!","TWN":"總、總之不可以！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"반대입니다요! 금지입니다요! 절대 못 보냅니다요!","JPN":"反対でやんす！　禁止でやんす！　絶対行かせないでやんす！","ENG":"Vetoed! Overruled! Over my dead body!","TWN":"反對！禁止！我絕對不會讓你去的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……말이 안 통하는 꼬맹이네.","JPN":"……話の通じないチビだな。","ENG":"...There's no getting through with this kid.","TWN":"……小鬼真難溝通。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이봐, 당신이 메이즈의 전대장이야?","JPN":"おい、あなたがメイズの戦隊長か？","ENG":"Hey, are you the Maze's Commander?","TWN":"嘿，你是梅茲戰隊長嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 관리국 제9 포격전대를 맡고 있는 류드밀라다.","JPN":"ごほん、管理局第9砲撃戦隊を任されているリュドミラだ。","ENG":"Ahem, I'm Lyudmila, the Commander of the Administration 9th Artillery Division. ","TWN":"咳，我是盧德米拉，管理局第9炮擊戰隊的負責人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전대마다 분위기가 다르다곤 하지만, 상관에게는 예의를 지켜주면 좋겠군.","JPN":"戦隊によって軍紀が異なるとはいえ、上官には礼儀をわきまえてほしいな。","ENG":"I know each division has its own color, but you should still pay your respects to your superior.","TWN":"雖說每個戰隊的文化都不一樣，但希望你能對上級保持禮貌。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히익!! 그새 또 사고쳤습니다요!! 신참 녀석!!","JPN":"キヒイ！！　またやらかしたでやんす！！　新入りのやつ！！","ENG":"Eep!! The rookie caused another scene!!","TWN":"吱！！那傢伙又闖禍了！這個新人！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L13_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"얼른 사과드리는 겁니다요!! 무릎꿇고 싹싹 비는 겁니다요!!","JPN":"早く謝罪するでやんす！！　土下座するでやんす！！","ENG":"Go apologize right now!! Kneel and beg her for forgiveness!!","TWN":"趕緊道歉！！跪下來求原諒！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……젠장.","JPN":"……くそ。","ENG":"...Crud.","TWN":"……可惡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"죄송합니다. 메이즈 전대장님.","JPN":"申し訳ございません、メイズ戦隊長。","ENG":"My apologies, Maze Commander.","TWN":"對不起。梅茲梅茲戰隊長。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"……엥?","JPN":"……えん？","ENG":"...Huh?","TWN":"……呃？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"부탁드리겠습니다! 저를 동료들이 있는 곳으로 데려다 주십시오!","JPN":"お願いします！　アタシを仲間たちのところに連れて行ってください！","ENG":"But please! Take me to where my comrades are!","TWN":"拜託你！帶我去同伴們所在的地方！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제가 반드시 모두를 구해내겠습니다!","JPN":"アタシが必ず皆を助けます！","ENG":"I promise I'll save everyone!","TWN":"我一定會拯救大家的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……대원, 이름은?","JPN":"……隊員、名前は？","ENG":"...You. What's your name?","TWN":"……隊員，你叫什麼名字？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"앨리스 브레이드우드입니다.","JPN":"アリス・ブレイドウッドです。","ENG":"It's Alice Braidwood.","TWN":"我叫艾莉絲·布雷德伍德。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래, 앨리스. 동료들을 생각하는 마음은 알겠다.","JPN":"そうか、アリス。仲間たちを思う気持ちはわかる。","ENG":"Very well, Alice. I understand how you feel about your comrades.","TWN":"很好，艾莉絲戰隊員。我理解你為同伴擔心的心情。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지금 가변 심도 좌표, 필하모닉 홀은 틀림없이 아비규환의 전장이겠지.","JPN":"しかし、可変深度座標フィルハーモニーホールは今間違いなく阿鼻叫喚の戦場になっているだろう。","ENG":"However, the variable depth coordinates, Philharmonic Hall, should be in complete chaos right now.","TWN":"但現在，可變深度，管弦樂廳絕對已經成為了一片混亂的戰場。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"자네 같은 신참에게는 아직 무리일지도 몰라.","JPN":"君のような新入りがそこに出向くのは、まだ早いかもしれない。","ENG":"It might be too much for a rookie like you.","TWN":"對於像你這樣的新人來說，也許會很吃力。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래도 괜찮겠나?","JPN":"それでも行くと言うのか？","ENG":"Are you sure about this?","TWN":"那樣你也要去嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……메이즈 전대장님.","JPN":"……メイズ戦隊長。","ENG":"...Maze Commander.","TWN":"……梅茲戰隊長。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저는 한때 화재 현장에서 존경하는 대장님과 동료들.","JPN":"アタシはかつて火災現場で尊敬してやまない隊長と仲間たち……","ENG":"I wasn't able to save the lives of the captain I respected,","TWN":"我曾經沒能在火災現場保護尊敬隊長和同伴。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그리고 한 아이의 목숨을 지키지 못했습니다.","JPN":"そして一人の子どもを救えなかったことがあります。","ENG":"my colleagues, and a small child in a fire incident.","TWN":"就連想要救下的孩子最後也失去了生命。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 타들어가는 불 속에서 홀로 살아 남았을 때.","JPN":"燃え盛る炎の中で一人生き残ったあの日。","ENG":"I was the only one who survived in that crackling fire,","TWN":"那時的我獨自在熊熊大火中倖存下來了……"},"stage":{"bg":"YAKSHA_02","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그때의 저는 아무것도 알지 못했고, 아무런 힘이 없었습니다.","JPN":"あの日のアタシは何も知らず、何の力もありませんでした。","ENG":"and at the time, I knew nothing and had no power.","TWN":"卻還懵懵懂懂，也沒有任何力量。"},"stage":{"bg":"YAKSHA_02","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하지만 지금은 다릅니다.","JPN":"ですが今は違います。","ENG":"But it's different now.","TWN":"但現在不同了。"},"stage":{"bg":"YAKSHA_02","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"지금의 저는 진실을 알게 되었고, 현실을 바꿀 힘이 있습니다.","JPN":"今のアタシは真実を知っていて、現実を変える力を持っています。","ENG":"Now, I know the truth and possess the power to alter reality.","TWN":"現在我知道了真相，我有能力改變現實。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그리고 두 번 다시 잃고 싶지 않은 동료가 있습니다.","JPN":"そして、二度と失いたくない仲間がいます。","ENG":"Also, I have colleagues that I never want to lose again.","TWN":"而且，我不想再次失去同伴了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이대로 아무것도 하지 않으면, 또다시 소중한 동료를 잃게 될지도 모릅니다.","JPN":"このまま何もせずにいたら、アタシはまた大切な仲間を失うことになるかもしれません。","ENG":"If I do nothing, I might lose another precious colleague again.","TWN":"如果我什麼都不做，很可能會再次失去珍貴的同伴。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니 나중에 후회가 남지 않도록.","JPN":"だから後悔を残さないように。","ENG":"So to not have any regrets.","TWN":"我討厭後悔。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제가 할 수 있는 일이라면, 무엇이든 하겠습니다.","JPN":"アタシにできることなら、何でもやります。","ENG":"I'm going to do anything I can.","TWN":"為此我會盡全力做我所能及的任何事情。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저는 소방관이고, 이 방화복은 저의 각오!","JPN":"アタシは消防士で、この防火服はアタシの覚悟です！","ENG":"I am a firefighter, and this fire suit is my determination!","TWN":"我是一名消防員，這件消防服就是我的決心！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다시는 제 앞에서 아무도 죽게 내버려 두지 않겠다고 다짐했습니다!","JPN":"もう二度と目の前で誰も死なせないと誓いました！","ENG":"I vowed to never let anyone die in front of me ever again!","TWN":"我向自己發誓，我不會再讓任何人死在我面前！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니 저를 현장에 데려다 주십시오. 메이즈 전대장님!","JPN":"ですからアタシを現場に連れてってください、メイズ戦隊長！","ENG":"So take me with you to the scene, Maze Commander!","TWN":"請帶我去現場吧。梅茲戰隊長！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……좋다.","JPN":"……いいだろう。","ENG":"...Very well.","TWN":"……好。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"자네의 그 각오. 마음에 들었어.","JPN":"君のその覚悟、気に入った。","ENG":"I like your determination.","TWN":"我很喜歡，你的決心。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"준비하도록, 앨리스. 함선에 추적장치를 탑재하는 즉시 전장으로 향하겠다.","JPN":"準備しろ、アリス。追跡装置の搭載が完了したら直ちに、戦場へ向かう。","ENG":"Get ready, Alice. We're heading immediately to the battlefield as soon as the tracking device is installed.","TWN":"準備好，艾莉絲。一旦跟蹤裝置安裝完畢，我們就會前往戰場。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우갸아악……!!","JPN":"うぎゃああっ……！！","ENG":"Uwaaagh...!!","TWN":"嗚哇啊啊……！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"자, 잠깐! 잠깐만입니다요! 메이즈 전대장님!","JPN":"ちょ、ちょっと、待ってくださいでやんす！　メイズ戦隊長！","ENG":"W-wait! Hold on a sec! Maze Commander!","TWN":"等、等等！請稍等一會兒！梅茲戰隊長！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L8_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"저희 부전대장님은 신참 녀석이 절대 작전에 참가하면 안 된다고 신신당부했습니다요!","JPN":"新入りのやつがぜったい作戦に参加してはいけないと、副戦隊長に頼み込まれたでやんす！","ENG":"Our Deputy Commander insisted that the rookie never participate!","TWN":"我們的副戰隊長一再囑咐我們，絕對不能讓新人參加作戰的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아.","JPN":"大丈夫だ。","ENG":"It's all right.","TWN":"沒關係。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전이 끝나면 내가 야크샤 부전대장에게 알아듣게 설명하겠다.","JPN":"作戦が終わったら、ヤクシャー副戦隊長には私からよく説明しておく。","ENG":"Once the operation is over, I will explain everything to her.","TWN":"作戰結束後，我會跟夜叉副戰隊長解釋清楚的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히이……!! 그런 이야기가 아니라……!!","JPN":"キヒイ……！！　そういう話じゃなくて……！！","ENG":"Eep...!! That's not what I'm worried about...!","TWN":"吱……！！我不是那個意思……！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"신참 녀석도 그렇습니다요!","JPN":"新入り、あなたもあなたでやんす！","ENG":"And you, rookie!","TWN":"你也是的！新人！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국의 연합 전대. 그리고 부전대장님마저 고전하는 전장입니다요!","JPN":"管理局の連合戦隊、それに副戦隊長も苦戦するほどの戦場でやんす！！","ENG":"This fight is one that even the Administration's coalition divisions and Deputy Commander are struggling with!","TWN":"管理局聯合戰隊，還有連副戰隊長都吃力的戰場！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"어차피 그런 꼴로 가봤자, 도움이 안 된다는 걸 왜 모릅니까요……!!","JPN":"そんな状態で参戦したところで、何の役にも立たないってなんでわからないでやんすか……！！","ENG":"Why can't you realize that you won’t be of any help even if you go like that...?!","TWN":"你為什麼不明白，不管你怎麼做，也沒有用的……！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……그런 건 나도 알고 있어.","JPN":"……そんなのわかってるよ。","ENG":"...I know that already.","TWN":"……這我也知道。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하지만 괜찮아. 힘이 부족하면 빌리면 되니까.","JPN":"でも大丈夫だ。力が足りないなら、借りればいい。","ENG":"But it's okay. If I need power, I'll just borrow it.","TWN":"不過沒關係。我有方法借力。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"대, 대체 누구한테 빌린다는 겁니까요?","JPN":"か、借りるって誰にでやんすか？","ENG":"B-borrow it from whom?","TWN":"借……你要向誰借？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"여기 있잖아.","JPN":"ここにあるじゃん。","ENG":"From this thing.","TWN":"這個。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"몸이 버텨주기만 한다면, 그 대가로 엄청나게 막대한 힘을 빌려주는 녀석이.","JPN":"体が耐えてさえくれれば、とんでもない力を貸してくれるヤツが。","ENG":"This thing will grant me enormous amounts of strength as long as my body can endure it.","TWN":"只要身體能夠承受，作為回報這傢伙就會借給我巨大的力量。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"라이오넬 전대장님의 비스트 클로……?","JPN":"ライオネル戦隊長のビーストクロー……？","ENG":"Commander Lionel's Beast Claw...?","TWN":"萊諾戰隊長的魔獸爪……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"설마 또 비스트 클로를 착용하겠다는 겁니까요?","JPN":"まさか、またそれを装備するつもりでやんすか？","ENG":"You're not going to try equipping it again, are you?","TWN":"你難道還想要再試一次？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그래, 꼬맹이. 약속은 잊지 않았겠지?","JPN":"ああ、チビ。忘れてないだろうな。","ENG":"I am, kid. Or did you forget our promise?","TWN":"沒錯，小鬼。你應該沒有忘記你的承諾吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK"},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 녀석을 다룰 수 있으면, 나한테 넘기기로 한 거 말이야.","JPN":"こいつが扱えたらアタシにくれるって約束。","ENG":"You said that I can have it if I can use it.","TWN":"如果我能駕馭這傢伙，你就把它交給我。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"무리라고 말하지 않았습니까요!","JPN":"だから無理だと言ったでやんす！","ENG":"But I told you that it's impossible!","TWN":"我都說不可能的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그건 라이오넬 전대장님의 체구에 맞게 설계된 고유무장!","JPN":"それはライオネル戦隊長の体格に合わせて設計した固有武装！","ENG":"That is a Unique Gear customed to fit only Commander Lionel!","TWN":"這件專屬裝備，是按照萊諾戰隊長的體型量身打造的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그런 체구로 감당할 수 있는 무장이 아니라고 몇 번이나 말하지 않았습니까요!!","JPN":"あなたのような体が耐えられる武装じゃないでやんす！　何回言えばわかるでやんすか！！","ENG":"I've told you countless times that it's not a gear that someone of your size can handle!","TWN":"我已經告訴過你多少次了，它不是你這種體型的人能夠駕馭的武器！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"시끄러워, 지금은 수단과 방법을 가릴 때가 아니잖아!","JPN":"うるさい、今そんなこと考えてる余裕はない！","ENG":"Shut up. Now's not the time to pick and choose!","TWN":"吵死了，現在可不是挑三揀四的時候！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 녀석이 위험하다면서……!","JPN":"あいつが危ないんだろ……！","ENG":"You said that she's in danger...!","TWN":"你說他們現在有危險……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키, 키힉!?","JPN":"き、キヒッ！？","ENG":"E-eep?!","TWN":"吱、吱？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무력할 수밖에 없었던 그때와는 달라.","JPN":"無力だったあの頃とは違う。","ENG":"A lot has changed since the days I couldn't help but be weak.","TWN":"與那時無能為力的我不同。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"지금, 나는 달라져야만 해……!","JPN":"今のアタシは、変わらなきゃならないんだ……！","ENG":"Now, I must change...!","TWN":"現在的我，有能力改變……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"화재 현장에서 구조자를 구하는데 수단이나 방법 같은 건 가리지 않아.","JPN":"火災現場で人を助ける時は手段を選ばない。","ENG":"I don't mind using any means necessary to rescue people in a fire.","TWN":"我會不惜一切手段和代價，拯救火災現場的求救者。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국의 정보와 힘이 있다면…… 지금까지는 구할 수 없었던 사람도 구할 수 있겠지.","JPN":"管理局の情報と力をもってすれば……今までは救えなかった人も救えるだろう。","ENG":"And if I have the Administration's intel and power... I'll be able to save others whom I couldn't save before.","TWN":"如果能借助管理局的資訊和力量……我們一定能夠拯救更多迄今為止無法拯救的人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니까 나를 전대원으로 받아줘, 주디 스위프트.","JPN":"だからアタシを戦隊に受け入れてくれ、ジュディ・スウィフト。","ENG":"So, I want you to accept me into your division, Judy Swift.","TWN":"所以，請接受我成為戰隊的一員，茱蒂·斯威福特。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다시는 아무도 내 앞에서 죽게 내버려두지 않겠어.","JPN":"もう二度と、目の間で誰かを死なせたりしない。","ENG":"I will not allow anyone to die on my watch anymore.","TWN":"我不會再讓任何人死在我面前。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게…… 타오르는 불속에서 홀로 살아남아버린 내가 짊어질 유일한 의무니까.","JPN":"それが……あの炎の中から一人生き残ってしまったアタシが背負うべき、唯一の義務だから。","ENG":"Because... that's the one duty that I must bear as the sole survivor of that fire.","TWN":"那是……我必須承擔的唯一義務，因為我是大火中唯一的倖存者。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하지만 스승님은 이렇게도 말씀하셨죠.","JPN":"でも師匠はこんなことも言ってましたよね。","ENG":"But you also said this to me, Master.","TWN":"但師父這樣說過吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>현실의 싸움이라는 건, 단순한 전투력 수치로 결정되는 게 아니다. </color>","JPN":"<color=#ffd34c>現実の戦いというものは、単に戦闘力の数値で決まるものではない。</color>","ENG":"<color=#ffd34c>But reality isn't all about numbers and categories.</color>","TWN":"<color=#ffd34c>戰鬥的勝負並非僅僅取決於戰鬥力數值的高低。</color>"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>강하다고 해서 반드시 이기는 것도 아니고, 약하다고 해서 반드시 지는 것도 아니다.</color>","JPN":"<color=#ffd34c>強いからと言って勝つわけでも、弱いからと言って負けるわけでもない。</color>","ENG":"<color=#ffd34c>Being strong doesn't necessarily mean you win, and being weak doesn't necessarily mean you lose.</color>","TWN":"<color=#ffd34c>強不代表著會贏，弱也不代表著會輸。</color>"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"헤헤, 걱정마세요, 스승님!","JPN":"へへ、大丈夫ですよ。師匠！","ENG":"Hehe, don't worry, Master!","TWN":"嘿嘿，師父，你就放心吧！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"전 스승님의 가르침대로, 항상 한계의 한계를 넘어왔으니까요!","JPN":"私は師匠の教え通り、いつも限界の限界を越えてきましたから！","ENG":"Because I've always been going beyond my limits, just like you taught me!","TWN":"我一直按照師父所教的那樣，不斷挑戰著自己的極限！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아직은 이렇게 멀리서 지켜보는 게 전부겠지만.","JPN":"今はこうして遠くから眺めるだけだが。","ENG":"Even if observing from afar is all you can do right now,","TWN":"雖然，現在的你只能遠遠地看著。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"관리국에 계속 있을 생각이라면, 저 녀석의 뒷모습을 마음 속에 새겨둬라.","JPN":"管理局に居続けるつもりなら、あいつの背中を忘れるな。","ENG":"if you're thinking of staying in the Administration, take the image of her back to the heart.","TWN":"但如果你打算繼續留在管理局，就好好記住那傢伙的背影吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"저 모습은 언젠가 네가 다다라야 할 모습이고, 또 누군가에게 보여주게 될 모습이니까.","JPN":"あれはいつかお前が辿り着かねばならない境地であり、また誰かに見せてやらねばならない姿なのだから。","ENG":"That is what you'll have to become and show to others one day.","TWN":"那將會是你總有一天會達到的樣子，也是別人會看到你的樣子。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"예를 들면, 너도 마찬가지야. 앨리스 브레이드우드.","JPN":"たとえば、あなたもそうよ。アリス・ブレイドウッド。","ENG":"For instance, like you, Alice Braidwood.","TWN":"比如說你也是。艾莉絲·布雷德伍德。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어렸을 때 화재를 겪은 뒤, 줄곧 소방관을 꿈 꿔왔지?","JPN":"子どもの頃火災を経験して、消防士になる夢を持つようになったんでしょう？","ENG":"After that fire incident you had when you were little, you've always dreamt of being a firefighter, right?","TWN":"你小時候因為經歷了火災，就一直夢想成為一名消防員吧？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 그 꿈을 이루기 위해, 지금껏 꾸준히 노력해서 결국 소방관이 되었잖아?","JPN":"その夢を叶えるために努力し続けた結果、消防士になれたのよね。","ENG":"And you worked hard to achieve that dream, eventually becoming one, didn't you?","TWN":"為了實現這個夢想，你非常努力，最終得願以償，對嗎？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다시 말해, 조금씩 CRF를 소모한 결과로써 외부의 현실을 개변했다고 할 수 있지.","JPN":"だから、少しずつCRFを消耗したことで外部の現実を改変させたってことになるね。","ENG":"In other words, as a result of consuming CRF in tiny portions, your external reality had changed.","TWN":"換句話說，這就是一點一點消耗CRF而改變外部現實的結果。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"아니야.","JPN":"違う。","ENG":"No.","TWN":"不。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"내가 개변하고 싶은 건, 외부의 현실 같은 거창한 게 아니야.","JPN":"外部の現実だの何だの、アタシが改変したいのはそんな大それたものじゃない。","ENG":"The thing I want to change isn't anything grand like changing the world.","TWN":"改變世界什麼的，對我來說太過宏大，太過遙遠了。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"세계가 어쩌고, 인과가 어쩌고 하는 허무맹랑한 이야기. 나는 전혀 관심 없다고.","JPN":"世界がどうとか、因果がどうとかいう現実味のない話に興味なんかない。","ENG":"I'm not interested in such grandiose and absurd ideas about causality, the world, and so on.","TWN":"世界也好，因果也罷，都是些無稽之談。我一點也不感興趣。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"요령은 카운터가 되기 전과 별반 다르지 않아.","JPN":"コツは、カウンターになる前とさして変わりはない。","ENG":"The trick is not much different from before I became a Counter.","TWN":"看來和成為制裁者之前沒有太大區別嘛。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내가 개변할 수 있는 건, 처음부터 나 자신 밖에 없었어.","JPN":"アタシが変えられるものは、最初から自分自身しかないんだ。","ENG":"Because the only thing that I can change is myself.","TWN":"從一開始，我唯一能改變的就是我自己。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이곳에서 겪었던 경험, 흘려왔던 땀, 만났던 인연, 다짐했던 각오, 그리고…….","JPN":"ここで経験したすべて、流した汗、出会った人々、誓った覚悟、そして……","ENG":"With the experiences I had, the sweat I shed, the relationships I met, the determination I made, and...","TWN":"我在這裡的經歷，我流過的汗水，遇到的人，做下的決心，還有……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"오직 하나뿐인 나의 <color=#ffd34c>바람</color>으로, 스스로를 개변하는 거야!","JPN":"たった一つの、アタシの<color=#ffd34c>願い</color>によって、自分を変えるんだ！","ENG":"my one and only <color=#ffd34c>wish</color>, I'm going to change myself!","TWN":"我的唯一<color=#ffd34c>希望</color>，所以，改變自己吧！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_26"},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 내 현실개변력이야!!","JPN":"それがアタシの現実改変力だ！","ENG":"This is my Counter Reality Force!","TWN":"這就是我CRF！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"서, 설마 이건……!?","JPN":"ま、まさかこれは……！？","ENG":"N-no way, it can't be...!","TWN":"哇，這不可能……？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"CRF의 느낌이 달라졌어.","JPN":"CRFの体感が変化した。","ENG":"The aura of her CRF changed.","TWN":"CRF的感覺變了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 이게 환상종의 인자가 발휘하는 힘인가.","JPN":"なるほど。これが幻想種の因子が発揮する力なのか。","ENG":"I see. So this is the power of the Bygone Factor.","TWN":"原來如此。這就是夢幻品種的力量嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제기랄……!!","JPN":"くっそ……！！","ENG":"Dammit...!!","TWN":"該死的……！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어차피 전대장이 되어야 한다면서? 그럼 조금 일찍 끌어다 쓸 뿐이잖아……!!","JPN":"どちらにしろ戦隊長になるしかないんだろ？　それなら、早々に使わせてくれよ……！！","ENG":"I still have to become the Commander, don't I? Then this is just advancing the timing...!!","TWN":"不是說我要成為戰隊長嗎？那就讓這天早一點來吧……！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"마음대로 날뛰게 해줄 테니까……!! 얌전히 내 말을 들으라고……!!","JPN":"好きなだけ暴れさせてやるから……！！　大人しく言うことを聞け……！！","ENG":"I'll let you run wild as much as you want...! So just listen to me...!!","TWN":"想要隨心所欲地狂奔嗎……！！只要乖乖聽我話……！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 빌어먹을 짐승 자식아!!","JPN":"このこんちくしょう野郎！！","ENG":"You stupid beast!!","TWN":"你這頭固執的野獸！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};